import React, { useState, useEffect, useCallback } from 'react';
import Layout from '../components/shared/Layout';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const ROLE_COLORS = {
  owner:   { bg:'rgba(124,58,237,0.12)', color:'#a855f7', border:'rgba(124,58,237,0.3)' },
  admin:   { bg:'rgba(37,99,235,0.12)',  color:'#3b82f6', border:'rgba(37,99,235,0.3)'  },
  manager: { bg:'rgba(22,163,74,0.12)',  color:'#16a34a', border:'rgba(22,163,74,0.3)'  },
  viewer:  { bg:'rgba(107,114,128,0.12)',color:'#6b7280', border:'rgba(107,114,128,0.3)'},
};

const ROLE_DESCRIPTIONS = {
  owner:   'Full access — manage team, billing, all campaigns and settings.',
  admin:   'Manage campaigns and team members, view billing.',
  manager: 'Create and edit campaigns, view analytics and performance.',
  viewer:  'Read-only access to campaigns and analytics.',
};

function RoleBadge({ role }) {
  const c = ROLE_COLORS[role] || ROLE_COLORS.viewer;
  return (
    <span style={{
      padding:'3px 10px', borderRadius:20, fontSize:11, fontWeight:700,
      background:c.bg, color:c.color, border:`1px solid ${c.border}`,
      textTransform:'capitalize', whiteSpace:'nowrap'
    }}>{role}</span>
  );
}

function timeAgo(date) {
  if (!date) return 'Never';
  const diff = (Date.now() - new Date(date)) / 1000;
  if (diff < 60)    return 'Just now';
  if (diff < 3600)  return `${Math.floor(diff/60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff/3600)}h ago`;
  if (diff < 86400*30) return `${Math.floor(diff/86400)}d ago`;
  return new Date(date).toLocaleDateString();
}

export default function TeamPage() {
  const { user } = useAuth();
  const [org, setOrg]               = useState(null);
  const [members, setMembers]       = useState([]);
  const [pendingInvites, setPendingInvites] = useState([]);
  const [loading, setLoading]       = useState(true);
  const [orgName, setOrgName]       = useState('');
  const [creating, setCreating]     = useState(false);
  const [showInviteForm, setShowInviteForm] = useState(false);
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole]   = useState('viewer');
  const [inviting, setInviting]       = useState(false);
  const [toast, setToast]             = useState({ msg:'', type:'info' });
  const [devInviteUrl, setDevInviteUrl] = useState('');
  const [resending, setResending]     = useState(null);

  const showToast = (msg, type='info') => {
    setToast({ msg, type });
    setTimeout(() => setToast({ msg:'', type:'info' }), 6000);
  };

  const fetchOrg = useCallback(async () => {
    try {
      const orgRes = await api.get('/organization/my');
      if (orgRes.data) {
        setOrg(orgRes.data);
        const membersRes = await api.get('/organization/my/members');
        setMembers(membersRes.data.members || []);
        setPendingInvites(membersRes.data.pendingInvites || []);
      }
    } catch {}
    finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchOrg(); }, [fetchOrg]);

  const handleCreateOrg = async () => {
    if (!orgName.trim()) return;
    setCreating(true);
    try {
      const res = await api.post('/organization', { name: orgName.trim() });
      setOrg(res.data);
      setMembers([{ userId: { _id: user.id, name: user.name, email: user.email }, role: 'owner', joinedAt: new Date() }]);
      setPendingInvites([]);
      showToast('✅ Organization created!', 'success');
    } catch (err) {
      showToast('❌ ' + (err.response?.data?.message || err.message), 'error');
    } finally { setCreating(false); }
  };

  const handleInvite = async () => {
    if (!inviteEmail.trim()) return;
    setInviting(true);
    setDevInviteUrl('');
    try {
      const res = await api.post('/organization/my/invite', {
        email: inviteEmail.trim().toLowerCase(),
        role: inviteRole
      });

      // Show dev invite URL if SMTP not configured
      if (res.data.acceptUrl) {
        setDevInviteUrl(res.data.acceptUrl);
      }

      showToast(res.data.message, res.data.emailSent ? 'success' : 'info');
      setInviteEmail('');
      setShowInviteForm(false);
      fetchOrg(); // refresh to show pending invite
    } catch (err) {
      showToast('❌ ' + (err.response?.data?.message || err.message), 'error');
    } finally { setInviting(false); }
  };

  const handleResend = async (email) => {
    setResending(email);
    try {
      const res = await api.post('/organization/my/invite/resend', { email });
      if (res.data.acceptUrl) setDevInviteUrl(res.data.acceptUrl);
      showToast(res.data.message, 'info');
      fetchOrg();
    } catch (err) {
      showToast('❌ ' + (err.response?.data?.message || err.message), 'error');
    } finally { setResending(null); }
  };

  const handleCancelInvite = async (email) => {
    try {
      await api.delete(`/organization/my/invite/${encodeURIComponent(email)}`);
      setPendingInvites(pi => pi.filter(i => i.email !== email));
      showToast('Invitation cancelled');
    } catch (err) {
      showToast('❌ ' + err.message, 'error');
    }
  };

  const handleRoleChange = async (memberId, newRole) => {
    try {
      await api.patch(`/organization/my/members/${memberId}`, { role: newRole });
      setMembers(ms => ms.map(m =>
        m.userId?._id === memberId ? { ...m, role: newRole } : m
      ));
      showToast('✅ Role updated', 'success');
    } catch (err) {
      showToast('❌ ' + (err.response?.data?.message || err.message), 'error');
    }
  };

  const handleRemove = async (memberId, memberName) => {
    if (!window.confirm(`Remove ${memberName} from the team?`)) return;
    try {
      await api.delete(`/organization/my/members/${memberId}`);
      setMembers(ms => ms.filter(m => m.userId?._id !== memberId));
      showToast(`Removed ${memberName}`);
    } catch (err) {
      showToast('❌ ' + (err.response?.data?.message || err.message), 'error');
    }
  };

  const isOwnerOrAdmin = members.some(m =>
    m.userId?._id === user?.id && ['owner', 'admin'].includes(m.role)
  );

  const toastStyles = {
    success: { bg:'rgba(22,163,74,0.12)',  border:'rgba(22,163,74,0.3)'  },
    error:   { bg:'rgba(239,68,68,0.12)',  border:'rgba(239,68,68,0.3)'  },
    info:    { bg:'rgba(37,99,235,0.1)',   border:'rgba(37,99,235,0.25)' },
  };

  return (
    <Layout>
      {/* Toast */}
      {toast.msg && (
        <div style={{
          position:'fixed', top:20, right:20, zIndex:9999, maxWidth:420,
          padding:'14px 18px', borderRadius:12,
          background: toastStyles[toast.type]?.bg || toastStyles.info.bg,
          border:`1px solid ${toastStyles[toast.type]?.border || toastStyles.info.border}`,
          boxShadow:'0 8px 32px rgba(0,0,0,0.2)', fontSize:13,
          color:'var(--text-primary)', animation:'slideIn 0.3s ease-out',
          display:'flex', gap:10, alignItems:'flex-start'
        }}>
          <span style={{ flex:1, lineHeight:1.5 }}>{toast.msg}</span>
          <button onClick={() => setToast({msg:'',type:'info'})}
            style={{ background:'none', border:'none', color:'var(--text-faint)', cursor:'pointer', fontSize:16, padding:0, flexShrink:0 }}>✕</button>
        </div>
      )}

      <div className="page-header">
        <div>
          <h1 className="page-title">Team Management</h1>
          <p className="page-subtitle">Manage your organization and collaborate with your team</p>
        </div>
        {org && isOwnerOrAdmin && (
          <button className="btn-primary" onClick={() => setShowInviteForm(!showInviteForm)}>
            + Invite Member
          </button>
        )}
      </div>

      {loading ? (
        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          {[1,2,3].map(i => <div key={i} className="skeleton" style={{ height:72, borderRadius:12 }}/>)}
        </div>

      ) : !org ? (
        /* ── Create Organization ── */
        <div style={{ maxWidth:540, margin:'0 auto' }}>
          <div className="glass-card" style={{ padding:40, textAlign:'center' }}>
            <div style={{ fontSize:56, marginBottom:16 }}>🏢</div>
            <h2 style={{ fontSize:20, fontWeight:800, color:'var(--text-primary)', margin:'0 0 8px' }}>
              Create Your Organization
            </h2>
            <p style={{ fontSize:13, color:'var(--text-muted)', margin:'0 0 28px', lineHeight:1.7 }}>
              Set up an organization to invite team members, assign roles and collaborate on ad campaigns together.
            </p>
            <div style={{ display:'flex', gap:10, justifyContent:'center' }}>
              <input
                className="form-input"
                placeholder="e.g. Acme Marketing Agency"
                value={orgName}
                onChange={e => setOrgName(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleCreateOrg()}
                style={{ maxWidth:300 }}
              />
              <button className="btn-primary" onClick={handleCreateOrg}
                disabled={creating || !orgName.trim()} style={{ flexShrink:0 }}>
                {creating ? '⏳...' : 'Create'}
              </button>
            </div>
          </div>

          {/* Role descriptions */}
          <div style={{ marginTop:20, display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(200px,1fr))', gap:12 }}>
            {Object.entries(ROLE_DESCRIPTIONS).filter(([r]) => r !== 'owner').map(([role, desc]) => {
              const c = ROLE_COLORS[role];
              return (
                <div key={role} style={{ padding:'14px 16px', borderRadius:12, background:'var(--bg-card)', border:`1px solid ${c.border}` }}>
                  <div style={{ fontSize:12, fontWeight:700, color:c.color, textTransform:'capitalize', marginBottom:6 }}>{role}</div>
                  <div style={{ fontSize:12, color:'var(--text-muted)', lineHeight:1.5 }}>{desc}</div>
                </div>
              );
            })}
          </div>
        </div>

      ) : (
        <>
          {/* ── Org Header ── */}
          <div className="glass-card" style={{ padding:22, marginBottom:20, display:'flex', gap:16, alignItems:'center', flexWrap:'wrap' }}>
            <div style={{
              width:52, height:52, borderRadius:14, flexShrink:0,
              background:'linear-gradient(135deg,#7c3aed,#a855f7)',
              display:'flex', alignItems:'center', justifyContent:'center', fontSize:24
            }}>🏢</div>
            <div style={{ flex:1 }}>
              <div style={{ fontSize:18, fontWeight:800, color:'var(--text-primary)', marginBottom:2 }}>{org.name}</div>
              <div style={{ fontSize:12, color:'var(--text-muted)' }}>
                {members.length} member{members.length !== 1 ? 's' : ''}
                {pendingInvites.length > 0 && ` · ${pendingInvites.length} pending invite${pendingInvites.length !== 1 ? 's' : ''}`}
                {' · Plan: '}
                <span style={{ color:'var(--purple-light)', fontWeight:600, textTransform:'capitalize' }}>{org.plan || 'starter'}</span>
              </div>
            </div>
            <div style={{ display:'flex', gap:20 }}>
              {[
                { label:'Members', value:members.length },
                { label:'Active',  value:members.filter(m=>m.role!=='viewer').length },
                { label:'Pending', value:pendingInvites.length },
              ].map(s => (
                <div key={s.label} style={{ textAlign:'center' }}>
                  <div style={{ fontSize:20, fontWeight:800, color:'var(--text-primary)' }}>{s.value}</div>
                  <div style={{ fontSize:11, color:'var(--text-faint)' }}>{s.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* ── Dev invite URL display (when SMTP not configured) ── */}
          {devInviteUrl && (
            <div style={{
              padding:'16px 20px', borderRadius:12, marginBottom:16,
              background:'rgba(37,99,235,0.08)', border:'1px solid rgba(37,99,235,0.25)',
              display:'flex', flexDirection:'column', gap:10
            }}>
              <div style={{ fontSize:13, fontWeight:700, color:'#3b82f6' }}>
                📧 SMTP not configured — share this link manually:
              </div>
              <div style={{ display:'flex', gap:10, alignItems:'center', flexWrap:'wrap' }}>
                <input
                  readOnly value={devInviteUrl}
                  style={{ flex:1, padding:'8px 12px', borderRadius:8, background:'var(--bg-input)', border:'1px solid var(--border-subtle)', color:'var(--text-primary)', fontSize:12, fontFamily:'DM Mono,monospace', minWidth:0 }}
                  onClick={e => e.target.select()}
                />
                <button className="btn-secondary" style={{ fontSize:12, flexShrink:0 }}
                  onClick={() => { navigator.clipboard.writeText(devInviteUrl); showToast('✅ Link copied!', 'success'); }}>
                  📋 Copy Link
                </button>
              </div>
              <div style={{ fontSize:11, color:'var(--text-faint)' }}>
                To send real emails: add SMTP_USER and SMTP_PASS to server/.env
              </div>
            </div>
          )}

          {/* ── Invite Form ── */}
          {showInviteForm && isOwnerOrAdmin && (
            <div className="glass-card" style={{ padding:24, marginBottom:20 }}>
              <h3 style={{ fontSize:15, fontWeight:700, color:'var(--text-primary)', margin:'0 0 16px' }}>
                Invite a Team Member
              </h3>

              <div style={{ display:'grid', gridTemplateColumns:'1fr auto auto', gap:10, alignItems:'end', flexWrap:'wrap' }}>
                <div>
                  <label className="form-label">Email Address</label>
                  <input
                    className="form-input"
                    type="email"
                    placeholder="colleague@company.com"
                    value={inviteEmail}
                    onChange={e => setInviteEmail(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handleInvite()}
                  />
                </div>
                <div>
                  <label className="form-label">Role</label>
                  <select className="form-input" value={inviteRole}
                    onChange={e => setInviteRole(e.target.value)}
                    style={{ width:'auto', minWidth:130 }}>
                    <option value="viewer">Viewer</option>
                    <option value="manager">Manager</option>
                    <option value="admin">Admin</option>
                  </select>
                </div>
                <button className="btn-primary" onClick={handleInvite}
                  disabled={inviting || !inviteEmail.trim()} style={{ height:42 }}>
                  {inviting ? '⏳ Sending...' : '✉️ Send Invite'}
                </button>
              </div>

              {/* Role description */}
              <div style={{ marginTop:12, padding:'10px 14px', borderRadius:8, background:'var(--bg-elevated)', fontSize:12, color:'var(--text-muted)' }}>
                <strong style={{ color:ROLE_COLORS[inviteRole]?.color, textTransform:'capitalize' }}>{inviteRole}:</strong>{' '}
                {ROLE_DESCRIPTIONS[inviteRole]}
              </div>
            </div>
          )}

          {/* ── Members List ── */}
          <div className="glass-card" style={{ padding:24, marginBottom:20 }}>
            <h3 style={{ fontSize:16, fontWeight:700, color:'var(--text-primary)', margin:'0 0 20px' }}>
              Members ({members.length})
            </h3>
            <div style={{ display:'flex', flexDirection:'column' }}>
              {members.map((m, idx) => {
                const memberUser = m.userId || {};
                const isMe       = memberUser._id === user?.id;
                const isOwner    = m.role === 'owner';
                const canManage  = isOwnerOrAdmin && !isMe && !isOwner;

                return (
                  <div key={idx} style={{
                    display:'flex', alignItems:'center', gap:14,
                    padding:'14px 0',
                    borderBottom: idx < members.length - 1 ? '1px solid var(--border-subtle)' : 'none',
                    flexWrap:'wrap'
                  }}>
                    {/* Avatar */}
                    <div style={{
                      width:40, height:40, borderRadius:'50%', flexShrink:0,
                      background:`linear-gradient(135deg,${ROLE_COLORS[m.role]?.color || '#7c3aed'},${ROLE_COLORS[m.role]?.color || '#a855f7'}88)`,
                      display:'flex', alignItems:'center', justifyContent:'center',
                      fontSize:16, fontWeight:700, color:'white'
                    }}>
                      {memberUser.name?.[0]?.toUpperCase() || '?'}
                    </div>

                    {/* Info */}
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ display:'flex', alignItems:'center', gap:8, flexWrap:'wrap', marginBottom:2 }}>
                        <span style={{ fontSize:14, fontWeight:700, color:'var(--text-primary)' }}>
                          {memberUser.name || 'Unknown'}
                        </span>
                        {isMe && (
                          <span style={{ fontSize:10, padding:'2px 7px', borderRadius:10, background:'rgba(124,58,237,0.15)', color:'var(--purple-light)', fontWeight:700 }}>
                            You
                          </span>
                        )}
                        <RoleBadge role={m.role} />
                      </div>
                      <div style={{ fontSize:12, color:'var(--text-faint)' }}>
                        {memberUser.email}
                        {m.joinedAt && ` · Joined ${timeAgo(m.joinedAt)}`}
                        {memberUser.lastLogin && ` · Last active ${timeAgo(memberUser.lastLogin)}`}
                      </div>
                    </div>

                    {/* Actions */}
                    {canManage && (
                      <div style={{ display:'flex', gap:8, flexShrink:0 }}>
                        <select
                          value={m.role}
                          onChange={e => handleRoleChange(memberUser._id, e.target.value)}
                          style={{ padding:'5px 10px', borderRadius:8, border:'1px solid var(--border-subtle)', background:'var(--bg-input)', color:'var(--text-primary)', fontSize:12, cursor:'pointer' }}
                        >
                          <option value="viewer">Viewer</option>
                          <option value="manager">Manager</option>
                          <option value="admin">Admin</option>
                        </select>
                        <button onClick={() => handleRemove(memberUser._id, memberUser.name)}
                          style={{ padding:'5px 10px', borderRadius:8, border:'1px solid rgba(239,68,68,0.3)', background:'rgba(239,68,68,0.08)', color:'#ef4444', cursor:'pointer', fontSize:12, fontWeight:600 }}>
                          Remove
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* ── Pending Invitations ── */}
          {pendingInvites.length > 0 && (
            <div className="glass-card" style={{ padding:24 }}>
              <h3 style={{ fontSize:16, fontWeight:700, color:'var(--text-primary)', margin:'0 0 20px' }}>
                Pending Invitations ({pendingInvites.length})
              </h3>
              <div style={{ display:'flex', flexDirection:'column' }}>
                {pendingInvites.map((inv, idx) => {
                  const expired = new Date(inv.expiresAt) < new Date();
                  return (
                    <div key={idx} style={{
                      display:'flex', alignItems:'center', gap:14,
                      padding:'14px 0',
                      borderBottom: idx < pendingInvites.length - 1 ? '1px solid var(--border-subtle)' : 'none',
                      flexWrap:'wrap', opacity: expired ? 0.6 : 1
                    }}>
                      <div style={{ width:40, height:40, borderRadius:'50%', flexShrink:0, background:'var(--bg-elevated)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:18 }}>
                        ✉️
                      </div>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:14, fontWeight:600, color:'var(--text-primary)', marginBottom:2 }}>
                          {inv.email}
                        </div>
                        <div style={{ fontSize:12, color:'var(--text-faint)' }}>
                          Invited as <strong style={{ color:ROLE_COLORS[inv.role]?.color, textTransform:'capitalize' }}>{inv.role}</strong>
                          {' · '}
                          {expired
                            ? <span style={{ color:'#ef4444' }}>Expired</span>
                            : `Expires ${timeAgo(inv.expiresAt)}`}
                        </div>
                      </div>
                      {isOwnerOrAdmin && (
                        <div style={{ display:'flex', gap:8, flexShrink:0 }}>
                          <button
                            onClick={() => handleResend(inv.email)}
                            disabled={resending === inv.email}
                            style={{ padding:'5px 12px', borderRadius:8, border:'1px solid var(--border-subtle)', background:'var(--bg-elevated)', color:'var(--text-muted)', cursor:'pointer', fontSize:12, fontWeight:600 }}
                          >
                            {resending === inv.email ? '⏳...' : '🔄 Resend'}
                          </button>
                          <button
                            onClick={() => handleCancelInvite(inv.email)}
                            style={{ padding:'5px 10px', borderRadius:8, border:'1px solid rgba(239,68,68,0.3)', background:'rgba(239,68,68,0.08)', color:'#ef4444', cursor:'pointer', fontSize:12, fontWeight:600 }}
                          >
                            Cancel
                          </button>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </>
      )}
    </Layout>
  );
}
